<?php/*入力漏れチェック第1引数：入力項目第2引数：入力内容戻り値：エラーフラグ、項目数、エラー内容*/function input_check ($items) {	//項目がなくなるまで	$rtn = "";	while (list($key, $val) = each($items)) {		//値がない時		if (!$val) {			//エラーフラグを立てる			$rtn .= "<p class=\"error\">" .$key. "を入力してください。</p>\n";		}	}	return ($rtn);}function katakana_check ($text) {	$rtn = "";	$str="アイウエオカキクケコサシスセソタチツテトナニヌネノハヒフヘホマミムメモヤユヨラリルレロワヲンガギグゲゴザジズゼゾダヂヅデドパピプペポバビブベボッァィゥェォャュョヮー";	if((!preg_match("/^[$str]+$/u", $text))){		$rtn .= "<p class=\"error\">フリガナが正しく記載されていません。</p>\n";	}	return($rtn);}/*電話番号フォーマットチェック引数：入力された電話番号戻り値：エラーメッセージ*/function tel_check ($tel) {	$rtn = "";	if(!eregi("^([0-9]+)-([a-z,0-9,-]+)",$tel)){		$rtn .= "<p class=\"error\">電話番号が正しく記載されていません。</p>\n";	}	return($rtn);}/*メールアドレスフォーマットチェック第1引数：入力されたメールアドレス第2引数：入力されたメールアドレス確認用戻り値：正しい：0、フォーマットエラー：1*/function mail_check ($mail,$vmail) {	$rtn = "";	//フォーマットチェック	if(!ereg("^[^@]+@[^.]+\..+", $mail)){		$rtn .= "<p class=\"error\">メールアドレスが正しく記載されていません。</p>\n";	}/*	if(!ereg("^[^@]+@[^.]+\..+", $vmail)){		$rtn .= "<p class=\"error\">メールアドレス：確認用が正しく記載されていません。</p>\n";	}*/	//確認用と同じメールアドレスが入力されているかどうか	if ($mail != $vmail) {		$rtn .= "<p class=\"error\">メールアドレスが一致しません。</p>\n";	}	return($rtn);}?>